 43	    private sealed class InMemoryXmlRepository : IXmlRepository
 44	    {
 45	        private readonly List<XElement> _elements = [];
 46	
 47	        public IReadOnlyCollection<XElement> GetAllElements()
 48	        {
 49	            lock (_elements)
 50	            {
